import os
import re
import unicodedata
from flask import Flask, send_from_directory, abort, redirect, url_for, request

app = Flask(__name__)

# Configuration
UPLOAD_FOLDER = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'uploads')
app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER

# Ensure uploads directory exists
os.makedirs(UPLOAD_FOLDER, exist_ok=True)


def sanitize_filename(filename):
    """Sanitize filename to prevent directory traversal attacks."""
    # Remove any directory components
    filename = os.path.basename(filename)
    # Remove null bytes
    filename = filename.replace('\x00', '')
    return filename


def normalize_legacy_filename(filename):
    """
    Convert modern filenames to possible legacy naming conventions and vice versa.
    Supports multiple legacy naming patterns that users may depend on.
    """
    candidates = [filename]

    # Legacy convention 1: spaces were replaced with underscores
    candidates.append(filename.replace(' ', '_'))
    candidates.append(filename.replace('_', ' '))

    # Legacy convention 2: spaces were replaced with hyphens
    candidates.append(filename.replace(' ', '-'))
    candidates.append(filename.replace('-', ' '))

    # Legacy convention 3: underscores and hyphens were interchangeable
    candidates.append(filename.replace('-', '_'))
    candidates.append(filename.replace('_', '-'))

    # Legacy convention 4: filenames were lowercased
    candidates.append(filename.lower())
    candidates.append(filename.lower().replace(' ', '_'))
    candidates.append(filename.lower().replace(' ', '-'))
    candidates.append(filename.lower().replace('-', '_'))
    candidates.append(filename.lower().replace('_', '-'))

    # Legacy convention 5: filenames were uppercased
    candidates.append(filename.upper())

    # Legacy convention 6: special characters were stripped
    stripped = re.sub(r'[^\w\.\-]', '', filename)
    candidates.append(stripped)
    candidates.append(stripped.lower())

    # Legacy convention 7: multiple extensions (e.g., file.backup.txt -> file.txt)
    name, ext = os.path.splitext(filename)
    if '.' in name:
        base_name = name.split('.')[0]
        candidates.append(base_name + ext)
        candidates.append(base_name.lower() + ext)
        candidates.append(base_name.replace(' ', '_') + ext)

    # Legacy convention 8: URL-encoded characters (e.g., %20 for spaces)
    try:
        from urllib.parse import unquote, quote
        candidates.append(unquote(filename))
        candidates.append(quote(filename, safe='.-_'))
    except ImportError:
        pass

    # Legacy convention 9: Unicode normalization (NFC vs NFD)
    candidates.append(unicodedata.normalize('NFC', filename))
    candidates.append(unicodedata.normalize('NFD', filename))
    candidates.append(unicodedata.normalize('NFKC', filename))
    candidates.append(unicodedata.normalize('NFKD', filename))

    # Legacy convention 10: parentheses in duplicate filenames e.g., file(1).txt -> file_1.txt
    paren_match = re.match(r'^(.+)\((\d+)\)(\.\w+)$', filename)
    if paren_match:
        base, num, ext = paren_match.groups()
        candidates.append(f"{base.strip()}{ext}")
        candidates.append(f"{base.strip()}_{num}{ext}")
        candidates.append(f"{base.strip()}-{num}{ext}")

    # Legacy convention 11: without copy suffix pattern (e.g., file - Copy.txt -> file.txt)
    copy_match = re.match(r'^(.+?)[\s\-_]*(copy|Copy|COPY)[\s\-_]*(\d*)(\.\w+)$', filename)
    if copy_match:
        base = copy_match.group(1).strip()
        ext = copy_match.group(4)
        candidates.append(f"{base}{ext}")

    # Remove duplicates while preserving order
    seen = set()
    unique_candidates = []
    for c in candidates:
        if c not in seen:
            seen.add(c)
            unique_candidates.append(c)

    return unique_candidates


def find_file(filename):
    """
    Try to find the file using various legacy naming conventions.
    Returns the actual filename on disk if found, None otherwise.
    """
    upload_folder = app.config['UPLOAD_FOLDER']

    # First, try exact match
    filepath = os.path.join(upload_folder, filename)
    if os.path.isfile(filepath):
        return filename

    # Try legacy naming conventions
    candidates = normalize_legacy_filename(filename)
    for candidate in candidates:
        candidate = sanitize_filename(candidate)
        filepath = os.path.join(upload_folder, candidate)
        if os.path.isfile(filepath):
            return candidate

    # Last resort: case-insensitive search in the directory
    try:
        files_in_dir = os.listdir(upload_folder)
        filename_lower = filename.lower()
        for f in files_in_dir:
            if f.lower() == filename_lower:
                return f

        # Try case-insensitive match with legacy candidates
        files_lower_map = {f.lower(): f for f in files_in_dir}
        for candidate in candidates:
            candidate = sanitize_filename(candidate)
            actual = files_lower_map.get(candidate.lower())
            if actual and os.path.isfile(os.path.join(upload_folder, actual)):
                return actual
    except OSError:
        pass

    return None


@app.route('/uploads/<path:filename>')
def serve_upload(filename):
    """
    Serve static files from the uploads directory with legacy filename support.
    Supports backward compatibility with older file naming conventions.
    """
    # Sanitize the requested filename
    filename = sanitize_filename(filename)

    if not filename:
        abort(400, description="Invalid filename")

    # Prevent directory traversal
    requested_path = os.path.realpath(os.path.join(app.config['UPLOAD_FOLDER'], filename))
    upload_folder_real = os.path.realpath(app.config['UPLOAD_FOLDER'])
    if not requested_path.startswith(upload_folder_real + os.sep) and requested_path != upload_folder_real:
        abort(403, description="Access denied")

    # Try to find the file with legacy support
    actual_filename = find_file(filename)

    if actual_filename is None:
        abort(404, description=f"File '{filename}' not found")

    # If the actual filename differs from requested, optionally redirect
    # to the canonical URL (configurable behavior)
    if actual_filename != filename and app.config.get('LEGACY_REDIRECT', False):
        return redirect(url_for('serve_upload', filename=actual_filename), code=301)

    return send_from_directory(
        app.config['UPLOAD_FOLDER'],
        actual_filename,
        as_attachment=request.args.get('download', '').lower() in ('1', 'true', 'yes')
    )


@app.route('/uploads/')
def list_uploads():
    """List available files in the uploads directory (optional, for debugging)."""
    if not app.config.get('ALLOW_LISTING', False):
        abort(403, description="Directory listing not allowed")

    try:
        files = os.listdir(app.config['UPLOAD_FOLDER'])
        files = [f for f in files if os.path.isfile(os.path.join(app.config['UPLOAD_FOLDER'], f))]
        files.sort()
        return {
            'files': files,
            'count': len(files)
        }
    except OSError as e:
        abort(500, description=f"Error listing directory: {str(e)}")


@app.route('/legacy-lookup/<path:filename>')
def legacy_lookup(filename):
    """
    API endpoint to check what a legacy filename resolves to.
    Useful for debugging and migration purposes.
    """
    filename = sanitize_filename(filename)
    candidates = normalize_legacy_filename(filename)
    actual = find_file(filename)

    return {
        'requested': filename,
        'resolved': actual,
        'candidates_checked': candidates,
        'found': actual is not None
    }


@app.errorhandler(404)
def not_found(error):
    return {
        'error': 'Not Found',
        'message': str(error.description) if hasattr(error, 'description') else 'Resource not found'
    }, 404


@app.errorhandler(400)
def bad_request(error):
    return {
        'error': 'Bad Request',
        'message': str(error.description) if hasattr(error, 'description') else 'Invalid request'
    }, 400


@app.errorhandler(403)
def forbidden(error):
    return {
        'error': 'Forbidden',
        'message': str(error.description) if hasattr(error, 'description') else 'Access denied'
    }, 403


# Configuration defaults
app.config.setdefault('LEGACY_REDIRECT', False)  # Set to True to redirect to canonical filenames
app.config.setdefault('ALLOW_LISTING', False)  # Set to True to allow directory listing


